code = """import json
import re

# Load the full books data
books_path = locals().get('var_functions.query_db:16')
if isinstance(books_path, str) and books_path.endswith('.json'):
    with open(books_path, 'r') as f:
        books = json.load(f)
else:
    books = []

# Initialize data structure
book_data = []

year_pattern = re.compile(r'\b(\d{4})\b')

for book in books:
    try:
        rating_num = int(book.get('rating_number', 0))
        if rating_num <= 0:
            continue
            
        details = book.get('details', '')
        if not details:
            continue
            
        match = year_pattern.search(details)
        if match:
            year = int(match.group(1))
            decade = (year // 10) * 10
            
            book_data.append({
                'book_id': book.get('book_id'),
                'rating_number': rating_num,
                'year': year,
                'decade': decade
            })
    except Exception as e:
        continue

print('__RESULT__:')
print(json.dumps({
    'total_books': len(books),
    'rated_books': len(book_data),
    'year_extracted_books': len(book_data),
    'sample_entries': book_data[:5]
}))"""

